package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithCommentMarker() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        char commentChar = '#';

        CSVFormat newFormat = baseFormat.withCommentMarker(commentChar);

        assertNotNull(newFormat);
        assertNotSame(baseFormat, newFormat);
        assertEquals(Character.valueOf(commentChar), newFormat.getCommentMarker());

        // Also test with default comment marker null
        CSVFormat formatWithNullComment = baseFormat.withCommentMarker((Character) null);
        assertNull(formatWithNullComment.getCommentMarker());
    }
}
